"""
Команда импорта данных из CSV-файлов.

Использование:
    python manage.py import_data

Ожидает CSV-файлы в папке import_data/:
    - products.csv     (или Tovar.csv)
    - user_import.csv
    - Заказ_import.csv
    - Пункты выдачи_import.csv
"""
import csv
import os
import shutil
from datetime import datetime
from decimal import Decimal, InvalidOperation
from pathlib import Path

from django.core.management.base import BaseCommand, CommandError
from django.db import connection

from core.models import (
    Role, User, Category, Manufacturer, Supplier,
    Product, PickupPoint, Order, OrderItem,
)


BASE_DIR = Path(__file__).resolve().parent.parent.parent.parent
IMPORT_DIR = BASE_DIR / 'import_data'


def parse_decimal(value):
    """Парсит десятичное число (поддержка запятой как разделителя)."""
    if not value:
        return Decimal('0')
    value = str(value).strip().replace(',', '.').replace(' ', '')
    try:
        return Decimal(value)
    except InvalidOperation:
        return Decimal('0')


def parse_date(value):
    """Парсит дату в нескольких форматах."""
    if not value:
        return None
    value = str(value).strip()
    for fmt in ('%d.%m.%Y', '%Y-%m-%d', '%d/%m/%Y', '%m/%d/%Y'):
        try:
            return datetime.strptime(value, fmt).date()
        except ValueError:
            continue
    return None


def read_csv(filename):
    """Читает CSV-файл, пробуя разные кодировки и разделители."""
    filepath = IMPORT_DIR / filename
    if not filepath.exists():
        return None

    for encoding in ('utf-8-sig', 'utf-8', 'cp1251', 'latin-1'):
        try:
            with open(filepath, 'r', encoding=encoding) as f:
                sample = f.read(4096)
                f.seek(0)
                first_line = sample.split('\n')[0]
                if ';' in first_line:
                    delimiter = ';'
                elif '\t' in first_line:
                    delimiter = '\t'
                else:
                    delimiter = ','
                reader = csv.DictReader(f, delimiter=delimiter)
                rows = list(reader)
                if rows:
                    return rows
        except (UnicodeDecodeError, csv.Error):
            continue
    return None


def find_column(row, *possible_names):
    """Находит значение колонки по списку возможных имён."""
    for name in possible_names:
        name_lower = name.lower().strip()
        for key in row:
            if key and key.lower().strip() == name_lower:
                return row[key] or ''
    return ''


def reset_sequence(model):
    """Сбрасывает auto-increment последовательность PostgreSQL."""
    table = model._meta.db_table
    with connection.cursor() as cursor:
        cursor.execute(
            f"SELECT setval(pg_get_serial_sequence('{table}', 'id'), "
            f"COALESCE(MAX(id), 1)) FROM {table}"
        )


class Command(BaseCommand):
    help = 'Импорт данных из CSV-файлов в папке import_data/'

    def handle(self, *args, **options):
        if not IMPORT_DIR.exists():
            raise CommandError(f'Папка {IMPORT_DIR} не найдена.')

        self.import_roles()
        self.import_pickup_points()
        self.import_products()
        self.import_users()
        self.import_orders()
        self.stdout.write(self.style.SUCCESS('Импорт завершён!'))

    def import_roles(self):
        """Создаёт стандартные роли."""
        for name in ['Администратор', 'Менеджер', 'Клиент']:
            Role.objects.get_or_create(name=name)
        self.stdout.write('  Роли: OK')

    def import_pickup_points(self):
        """Импорт пунктов выдачи."""
        rows = read_csv('Пункты выдачи_import.csv') or read_csv('pp.csv')
        if not rows:
            self.stdout.write(self.style.WARNING('  Пункты выдачи: файл не найден'))
            return

        for row in rows:
            address = (
                find_column(row, 'Адрес пункта выдачи', 'Адрес', 'address')
            ).strip()
            if address:
                PickupPoint.objects.get_or_create(address=address)

        reset_sequence(PickupPoint)
        self.stdout.write(f'  Пункты выдачи: {PickupPoint.objects.count()}')

    def import_products(self):
        """Импорт товаров."""
        rows = (
            read_csv('products.csv') or
            read_csv('Tovar.csv') or
            read_csv('product_import.csv')
        )
        if not rows:
            self.stdout.write(self.style.WARNING('  Товары: файл не найден'))
            return

        for row in rows:
            article = find_column(row, 'Артикул товара', 'Артикул', 'article').strip()
            if not article:
                continue

            name = find_column(row, 'Наименование товара', 'Наименование', 'name').strip()
            unit = find_column(row, 'Единица измерения', 'Ед. изм.', 'unit').strip() or 'шт.'
            price = parse_decimal(find_column(row, 'Цена', 'price'))
            discount = parse_decimal(find_column(
                row, 'Действующая скидка', 'Размер скидки', 'Текущая скидка', 'Скидка', 'discount'
            ))
            quantity = int(parse_decimal(find_column(
                row, 'Количество на складе', 'Кол-во на складе', 'Кол-во', 'quantity'
            )))
            description = find_column(row, 'Описание', 'description').strip()

            cat_name = find_column(row, 'Категория товара', 'Категория', 'category').strip()
            mfr_name = find_column(row, 'Производитель', 'manufacturer').strip()
            sup_name = find_column(row, 'Поставщик', 'supplier').strip()

            category = None
            if cat_name:
                category, _ = Category.objects.get_or_create(name=cat_name)

            manufacturer = None
            if mfr_name:
                manufacturer, _ = Manufacturer.objects.get_or_create(name=mfr_name)

            supplier = None
            if sup_name:
                supplier, _ = Supplier.objects.get_or_create(name=sup_name)

            product, created = Product.objects.update_or_create(
                article=article,
                defaults={
                    'name': name,
                    'unit': unit,
                    'price': price,
                    'discount': discount,
                    'quantity': quantity,
                    'description': description,
                    'category': category,
                    'manufacturer': manufacturer,
                    'supplier': supplier,
                },
            )

            photo_name = find_column(row, 'Фото', 'Изображение', 'photo').strip()
            if photo_name:
                src = IMPORT_DIR / photo_name
                if src.exists():
                    dst_dir = BASE_DIR / 'media' / 'products'
                    dst_dir.mkdir(parents=True, exist_ok=True)
                    dst = dst_dir / photo_name
                    shutil.copy2(src, dst)
                    product.photo = f'products/{photo_name}'
                    product.save(update_fields=['photo'])

        reset_sequence(Product)
        reset_sequence(Category)
        reset_sequence(Manufacturer)
        reset_sequence(Supplier)
        self.stdout.write(f'  Товары: {Product.objects.count()}')

    def import_users(self):
        """Импорт пользователей."""
        rows = read_csv('user_import.csv') or read_csv('users.csv')
        if not rows:
            self.stdout.write(self.style.WARNING('  Пользователи: файл не найден'))
            return

        for row in rows:
            username = find_column(row, 'Логин', 'login', 'username').strip()
            if not username:
                continue

            password = find_column(row, 'Пароль', 'password').strip()
            full_name = find_column(row, 'ФИО', 'Имя', 'full_name', 'name').strip()
            role_name = find_column(row, 'Роль', 'role').strip()

            role = None
            if role_name:
                role, _ = Role.objects.get_or_create(name=role_name)

            user, created = User.objects.get_or_create(
                username=username,
                defaults={
                    'full_name': full_name,
                    'role': role,
                },
            )
            if created and password:
                user.set_password(password)
                user.save()

        reset_sequence(User)
        self.stdout.write(f'  Пользователи: {User.objects.count()}')

    def import_orders(self):
        """Импорт заказов. Формат артикулов: 'АРТ1, кол1, АРТ2, кол2, ...'"""
        rows = read_csv('Заказ_import.csv') or read_csv('orders.csv')
        if not rows:
            self.stdout.write(self.style.WARNING('  Заказы: файл не найден'))
            return

        for row in rows:
            order_date = parse_date(find_column(row, 'Дата заказа', 'order_date'))
            delivery_date = parse_date(find_column(row, 'Дата доставки', 'delivery_date'))

            if not order_date or not delivery_date:
                continue

            pp_raw = find_column(
                row, 'Адрес пункта выдачи', 'Пункт выдачи', 'pickup_point'
            ).strip()
            client_name = find_column(
                row, 'ФИО авторизированного клиента', 'Клиент', 'ФИО клиента', 'client'
            ).strip()
            status = find_column(row, 'Статус заказа', 'Статус', 'status').strip() or 'Новый'
            code = find_column(row, 'Код для получения', 'Код получения', 'pickup_code').strip()

            pickup_point = None
            if pp_raw.isdigit():
                pp_list = list(PickupPoint.objects.all().order_by('id'))
                idx = int(pp_raw) - 1
                if 0 <= idx < len(pp_list):
                    pickup_point = pp_list[idx]
            if not pickup_point and pp_raw:
                pickup_point, _ = PickupPoint.objects.get_or_create(address=pp_raw)

            client = None
            if client_name:
                client = User.objects.filter(full_name=client_name).first()
                if not client:
                    client = User.objects.filter(full_name__icontains=client_name).first()
                if not client:
                    client = User.objects.first()

            if not pickup_point or not client:
                continue

            status_map = {
                'новый': 'new', 'new': 'new',
                'завершён': 'completed', 'завершен': 'completed', 'completed': 'completed',
            }
            status_code = status_map.get(status.lower(), 'new')

            order = Order.objects.create(
                order_date=order_date,
                delivery_date=delivery_date,
                pickup_point=pickup_point,
                client=client,
                status=status_code,
                pickup_code=int(code) if code.isdigit() else None,
            )

            items_raw = find_column(
                row, 'Артикул заказа', 'Артикул товара', 'Товар', 'product'
            ).strip()
            if items_raw:
                parts = [p.strip() for p in items_raw.split(',')]
                i = 0
                while i < len(parts):
                    article = parts[i]
                    qty = 1
                    if i + 1 < len(parts) and parts[i + 1].isdigit():
                        qty = int(parts[i + 1])
                        i += 2
                    else:
                        i += 1
                    product = Product.objects.filter(article=article).first()
                    if product:
                        OrderItem.objects.create(
                            order=order, product=product, quantity=qty
                        )

        reset_sequence(Order)
        reset_sequence(OrderItem)
        self.stdout.write(f'  Заказы: {Order.objects.count()}')
